// // This module implements a 2:1 multiplexer with an enable signal. When en is high, the output should be in0; when en is low, the output should be in1.
module mux_2_1_en(
    input in0,
    input in1,
    input en,
    output reg out
);

always @(*) begin
    out = en ? in1 : in0;
end

endmodule
